#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;ll ans;
const int N=2e5+10;int *f[N],*g[N],buf[N<<4],*tmp=buf+2*N,n,mxs[N],mxd[N];vector<int> G[N];
inline void dfs(int u=1,int fa=0)
{
	mxs[u]=0;for(int v:G[u])if(v!=fa)
	{
		dfs(v,u);if(mxd[mxs[u]]<mxd[v])mxs[u]=v;
	}
	mxd[u]=mxd[mxs[u]]+1;
}
int cnt=0;
inline void DP(int u,int fa=0)
{
//	printf("%d %d\n",u,g[u][0]);
	if(mxs[u]){f[mxs[u]]=f[u]+1;g[mxs[u]]=g[u]-1;DP(mxs[u],u);}
	f[u][0]=1;ans+=g[u][0];for(int v:G[u])if(v!=fa&&v!=mxs[u])
	{
		f[v]=tmp;tmp+=mxd[v]<<1;g[v]=tmp;tmp+=mxd[v]<<1;DP(v,u);
//		cnt+=(mxd[v]<<2);
		rep(0,mxd[v]-1,i)ans+=g[u][i+1]*f[v][i]+(i?f[u][i-1]*g[v][i]:0);
		rep(0,mxd[v]-1,i)
		{
			g[u][i+1]+=f[u][i+1]*f[v][i];f[u][i+1]+=f[v][i];
			if(i)g[u][i-1]+=g[v][i];
		}
	}
}
int main()
{
//	FIN("data.in");
	n=read();rep(2,n,i){int x=read(),y=read();G[x].push_back(y);G[y].push_back(x);}
	dfs();f[1]=tmp;tmp+=mxd[1]<<1;g[1]=tmp;tmp+=mxd[1]<<1;DP(1,0);printf("%lld\n",ans);
}
